-- The Circle — Supabase schema + seed
-- Изпълни целия файл в Supabase: SQL Editor → New query → Paste → Run

create table if not exists venues (
  id text primary key,
  name text not null,
  type text,
  hood text,
  rating numeric,
  lat double precision,
  lng double precision,
  icon text,
  description text,
  hours text,
  phone text,
  events_count int
);

create table if not exists events (
  id text primary key,
  title text not null,
  cat text,
  venue_id text references venues(id) on delete set null,
  date text,
  day text,
  time text,
  price text,
  free boolean default false,
  featured boolean default false,
  outdoor boolean default false,
  going int default 0,
  interested int default 0,
  description text,
  org_name text,
  org_avatar text,
  grad text
);

-- Включваме Row Level Security
alter table venues enable row level security;
alter table events enable row level security;

-- Всеки може да ЧЕТЕ (публично приложение)
create policy "public read venues" on venues for select using (true);
create policy "public read events" on events for select using (true);

-- Само влезли (logged-in) потребители могат да пишат.
-- За начало, ако ползваш само анонимния ключ от админ панела,
-- размаркирай редовете по-долу, за да позволиш писане с anon ключ:
create policy "anon write venues" on venues for all using (true) with check (true);
create policy "anon write events" on events for all using (true) with check (true);

-- ============ НАЧАЛНИ ДАННИ ============


